public class ModParticles {
    public static final DefaultParticleType CUSTOM_PARTICLE = FabricParticleTypes.simple();
    public static void register() {
        Registry.register(Registries.PARTICLE_TYPE, new Identifier("modid", "custom_particle"), CUSTOM_PARTICLE);
    }
}

public class CustomParticle extends SpriteBillboardParticle {
    protected CustomParticle(ClientWorld world, double x, double y, double z, double velocityX, double velocityY, double velocityZ) {
        super(world, x, y, z, velocityX, velocityY, velocityZ);
        this.scale = 0.2f;
        this.maxAge = 40;
    }
    @Override
    public ParticleTextureSheet getType() { return ParticleTextureSheet.PARTICLE_SHEET_OPAQUE; }
}

public static class Factory implements ParticleFactory<DefaultParticleType> {
    private final SpriteProvider spriteProvider;
    public Factory(SpriteProvider spriteProvider) { this.spriteProvider = spriteProvider; }
    @Override
    public Particle createParticle(DefaultParticleType type, ClientWorld world, double x, double y, double z, double velocityX, double velocityY, double velocityZ) {
        CustomParticle particle = new CustomParticle(world, x, y, z, velocityX, velocityY, velocityZ);
        particle.setSprite(spriteProvider);
        return particle;
    }
}

for (int i = 0; i < 50; i++) {
    double offsetX = (random.nextDouble() - 0.5) * 2.0;
    double offsetY = random.nextDouble() * 2.0;
    double offsetZ = (random.nextDouble() - 0.5) * 2.0;
    world.addParticle(ModParticles.CUSTOM_PARTICLE, x + offsetX, y + offsetY, z + offsetZ, 0, 0.1, 0);
}
